// ============================================================================
// PREPARAR SERVICIO AGREGADO BASEROW - Agente Calendario Leraysi v4
// ============================================================================
// Bifurca en DOS caminos según tipo de operación:
//
// PATH A — TURNO ADICIONAL (es_turno_adicional = true):
//   Otra trabajadora hace SOLO el servicio nuevo → CREATE fila nueva
//   El turno original queda INTACTO (no se modifica)
//   La fila nueva tiene turno_padre_id para vincularlos
//
// PATH B — MISMA TRABAJADORA (bloque combinado):
//   UPDATE fila existente con campos pendientes (v3: separación responsabilidades)
//   Los datos definitivos se aplican via webhook de pago
// ============================================================================
// INPUT: BuscarTurnoBaserow (resultado de búsqueda con row_id)
// OUTPUT: Campos para Baserow Create o Update + _meta
// ============================================================================

// Datos del turno encontrado en Baserow (viene de BuscarTurnoBaserow / Get many rows)
const turnoEncontrado = $input.first().json;

// Datos de ParseAgentResponse
const data = $('ParseAgentResponse').first().json;

// ============================================================================
// VALIDACIÓN
// ============================================================================
if (!turnoEncontrado || !turnoEncontrado.id) {
  throw new Error('[PrepararServicioAgregadoBaserow] No se encontró el turno en Baserow. ' +
                  `odoo_turno_id buscado: ${data.odoo_turno_id}`);
}

const turnoRowId = turnoEncontrado.id;

// ============================================================================
// FORMATEAR FECHA
// ============================================================================
function formatBaserowDatetime(date) {
  const argentinaTime = new Date(date.getTime() - (3 * 60 * 60 * 1000));
  const offset = '-03:00';
  const year = argentinaTime.getUTCFullYear();
  const month = String(argentinaTime.getUTCMonth() + 1).padStart(2, '0');
  const day = String(argentinaTime.getUTCDate()).padStart(2, '0');
  const hours = String(argentinaTime.getUTCHours()).padStart(2, '0');
  const minutes = String(argentinaTime.getUTCMinutes()).padStart(2, '0');
  const seconds = String(argentinaTime.getUTCSeconds()).padStart(2, '0');
  return `${year}-${month}-${day}T${hours}:${minutes}:${seconds}${offset}`;
}

const ahora = new Date();
const expiraAt = new Date(ahora.getTime() + 15 * 60 * 1000); // 15 min para pagar

// ============================================================================
// PATH A: TURNO ADICIONAL — CREATE fila nueva
// ============================================================================
if (data.es_turno_adicional) {
  // hora_sugerida = hora del slot elegido (09:00 para JC, hora real del nuevo servicio)
  // hora_servicio_reubicado = hora reubicada del PADRE (servicio existente), NO del nuevo
  const horaAdicional = data.hora_sugerida || '09:00';
  const precioNuevo = Number(data.precio) || 0;
  const senaNuevo = Math.round(precioNuevo * 0.3);

  // ── REUBICACIÓN PADRE (Caso C: agregar JC a servicio corto, misma trabajadora) ──
  // Si Estrategia B calculó una hora reubicada para el servicio existente,
  // incluir update del padre en _meta para que n8n lo aplique pre-pago (holdea el slot)
  const horaReubicadaPadre = data.hora_servicio_reubicado || null;
  const padreNecesitaReubicacion = horaReubicadaPadre && data.servicio_reubicado === true;

  // Construir fila nueva (misma estructura que PrepararTurnoBaserow)
  const createFields = {
    // Fecha y hora
    fecha: data.fecha_turno
      ? data.fecha_turno + 'T' + horaAdicional + ':00-03:00'
      : null,
    hora: horaAdicional,

    // Relación con Lead (del turno padre)
    // Baserow link row fields vienen como [{id, value, ...}] → extraer solo IDs [219]
    clienta_id: Array.isArray(turnoEncontrado.clienta_id)
      ? turnoEncontrado.clienta_id.map(c => typeof c === 'object' ? c.id : c)
      : [],

    // Datos clienta (copiados del turno padre)
    // Pueden ser lookup fields (array de objetos) o texto plano
    nombre_clienta: Array.isArray(turnoEncontrado.nombre_clienta)
      ? (turnoEncontrado.nombre_clienta[0]?.value || data.nombre_clienta || '')
      : (turnoEncontrado.nombre_clienta || data.nombre_clienta || ''),
    telefono: Array.isArray(turnoEncontrado.telefono)
      ? (turnoEncontrado.telefono[0]?.value || data.telefono || '')
      : (turnoEncontrado.telefono || data.telefono || ''),
    email: Array.isArray(turnoEncontrado.email)
      ? (turnoEncontrado.email[0]?.value || data.email || '')
      : (turnoEncontrado.email || data.email || ''),

    // Servicio: SOLO el nuevo (no combinado)
    // Baserow multi-select espera array de display names: ["Pedicura"]
    // servicio_detalle es string ("Pedicura" o "Manicura simple + Pedicura")
    servicio: (data.servicio_detalle || '').split(' + ').filter(s => s.trim()),
    servicio_detalle: data.servicio_detalle || '',
    complejidad_maxima: data.complejidad_maxima || 'media',
    trabajadora: data.trabajadora || 'Companera',
    duracion_min: data.duracion_estimada || 60,

    // Precio: SOLO del servicio nuevo
    precio: precioNuevo,
    sena_monto: senaNuevo,
    sena_pagada: false,

    // Estado
    estado: 'pendiente_pago',

    // MercadoPago
    mp_preference_id: data.mp_preference_id || '',
    mp_link: data.link_pago || '',
    mp_payment_id: '',

    // Timestamps
    created_at: formatBaserowDatetime(ahora),
    expira_at: formatBaserowDatetime(expiraAt),

    // Vinculación con turno padre
    turno_padre_id: turnoRowId,
    // hora_pre_reubicacion: SOLO cuando el padre fue reubicado (Caso C/D) → usado por FiltrarExpirados para revert
    hora_pre_reubicacion: padreNecesitaReubicacion ? (data.hora_original_padre || turnoEncontrado.hora || '') : '',
    // fecha_pre_reubicacion: datetime original del padre antes de reubicación → para revert directo sin reconstruir
    fecha_pre_reubicacion: padreNecesitaReubicacion ? (turnoEncontrado.fecha || '') : '',

    // Odoo
    odoo_turno_id: data.odoo_turno_id || null,

    // Conversation
    conversation_id: turnoEncontrado.conversation_id || data.conversation_id || null,

    // Notas
    notas: `Servicio adicional. Turno original: #${turnoRowId} ` +
           `(${typeof turnoEncontrado.trabajadora === 'object' ? (turnoEncontrado.trabajadora?.value || 'Leraysi') : (turnoEncontrado.trabajadora || 'Leraysi')} ` +
           `${turnoEncontrado.hora || '?'} ` +
           `${turnoEncontrado.servicio_detalle || ''}). ` +
           `Creado el ${ahora.toLocaleDateString('es-AR')}.` +
           (padreNecesitaReubicacion ? ` Hora padre reubicada: ${turnoEncontrado.hora} → ${horaReubicadaPadre}.` : ''),
  };

  console.log(`[PrepararServicioAgregadoBaserow] PATH A: TURNO ADICIONAL. ` +
    `Padre: #${turnoRowId} (${turnoEncontrado.trabajadora}). ` +
    `Nuevo: ${data.trabajadora} ${horaAdicional} ${data.servicio_detalle}` +
    (padreNecesitaReubicacion ? `. Reubicar padre: ${turnoEncontrado.hora} → ${horaReubicadaPadre}` : ''));

  return [{
    json: {
      // Flag para que el IF node en n8n sepa que es CREATE (no UPDATE)
      _operacion: 'crear_turno_adicional',

      // Campos para Baserow Create Row
      ...createFields,

      // Metadata para FormatearRespuestaServicioAgregado
      _meta: {
        accion: data.accion,
        mensaje_para_clienta: data.mensaje_para_clienta,
        lead_row_id: data.lead_row_id,
        odoo_turno_id: data.odoo_turno_id,
        // Datos del turno padre (para desglose de seña en respuesta)
        turno_padre_row_id: turnoRowId,
        turno_precio_existente: turnoEncontrado.precio || 0,
        turno_sena_pagada: turnoEncontrado.sena_monto || 0,
        turno_servicio_existente: turnoEncontrado.servicio_detalle || '',
        turno_hora_original: turnoEncontrado.hora || '',
        turno_trabajadora_original: turnoEncontrado.trabajadora || 'Leraysi',
        turno_complejidad_padre: turnoEncontrado.complejidad_maxima?.value || turnoEncontrado.complejidad_maxima || 'media',
        // Reubicación padre (Caso C: agregar JC a servicio corto, misma trabajadora)
        reubicar_padre: padreNecesitaReubicacion ? {
          row_id: turnoRowId,
          hora_nueva: horaReubicadaPadre,
          fecha_nueva: data.fecha_turno
            ? data.fecha_turno + 'T' + horaReubicadaPadre + ':00-03:00'
            : null,
          hora_original: data.hora_original_padre || turnoEncontrado.hora || '',
        } : null,
        // Datos definitivos (para turno adicional son los mismos, no hay split)
        datos_definitivos: {
          servicio: data.servicio,
          servicio_detalle: data.servicio_detalle || '',
          hora: horaAdicional,
          duracion_min: data.duracion_estimada || 60,
          complejidad_maxima: data.complejidad_maxima || 'media',
          precio: precioNuevo,
          sena_monto: senaNuevo,
        },
      }
    }
  }];
}

// ============================================================================
// PATH B: MISMA TRABAJADORA — UPDATE fila existente (v3: separación responsabilidades)
// ============================================================================
const horaDefinitiva = data.hora_sugerida || turnoEncontrado.hora || '09:00';
const precioDefinitivo = data.precio;
const senaMonto = Math.round((precioDefinitivo || 0) * 0.3);

const datosDefinitivos = {
  servicio: data.servicio,
  servicio_detalle: data.servicio_detalle,
  hora: horaDefinitiva,
  duracion_min: data.duracion_estimada || 60,
  complejidad_maxima: data.complejidad_maxima || 'media',
  precio: precioDefinitivo,
  sena_monto: senaMonto,
};

const updateFields = {
  sena_pagada: false,
  estado: 'pendiente_pago',
  mp_preference_id: data.mp_preference_id || '',
  mp_link: data.link_pago || '',
  updated_at: formatBaserowDatetime(ahora),
  expira_at: formatBaserowDatetime(expiraAt),
  notas: `Servicio agregado el ${ahora.toLocaleDateString('es-AR')}. ` +
         `Servicios: ${data.servicio_detalle}. ` +
         `Total: $${precioDefinitivo?.toLocaleString('es-AR') || 0}. ` +
         `Seña diferencial: $${senaMonto.toLocaleString('es-AR')}. ` +
         `Pendiente de pago.`
};

console.log(`[PrepararServicioAgregadoBaserow] PATH B: UPDATE misma trabajadora. ` +
  `Row: #${turnoRowId}. Servicios: ${data.servicio_detalle}`);

return [{
  json: {
    _operacion: 'actualizar_turno_existente',
    row_id: turnoRowId,
    ...updateFields,
    _meta: {
      accion: data.accion,
      mensaje_para_clienta: data.mensaje_para_clienta,
      lead_row_id: data.lead_row_id,
      odoo_turno_id: data.odoo_turno_id,
      turno_precio_existente: turnoEncontrado.precio || 0,
      turno_sena_pagada: turnoEncontrado.sena_monto || 0,
      turno_servicio_existente: turnoEncontrado.servicio_detalle || '',
      datos_definitivos: datosDefinitivos,
    }
  }
}];

// ============================================================================
// FORMATEAR RESPUESTA SERVICIO AGREGADO - Agente Calendario Leraysi v4
// ============================================================================
// Construye la respuesta final cuando se agrega un servicio a turno existente.
// Bifurca entre:
//   PATH A — TURNO ADICIONAL: fila nueva creada (Create Row response)
//   PATH B — MISMA TRABAJADORA: fila existente actualizada (Update Row response)
// ============================================================================
// NODO: FormatearRespuestaServicioAgregado (Code)
// INPUT: ActualizarTurnoBaserow O CrearTurnoAdicionalBaserow (respuesta de Baserow)
// OUTPUT: Respuesta estructurada para Return → Master Agent
// ============================================================================

const baserowResponse = $input.first().json;

// Recuperar datos del nodo PrepararServicioAgregadoBaserow
const prepararData = $('PrepararServicioAgregadoBaserow').first().json;
const metaData = prepararData._meta;
const definitivos = metaData.datos_definitivos || {};

// El ID de la fila en Baserow (nueva o actualizada)
const turnoRowId = baserowResponse.id;
const esTurnoAdicional = prepararData._operacion === 'crear_turno_adicional';

// ============================================================================
// PATH A: TURNO ADICIONAL — Fila nueva creada
// ============================================================================
if (esTurnoAdicional) {
  const precioNuevo = definitivos.precio || 0;
  const senaNuevo = definitivos.sena_monto || Math.round(precioNuevo * 0.3);

  // ── Hora client-facing: si hay jornada completa (padre o hijo), su hora prevalece ──
  // La clienta llega a las 09:00 para jornada completa, sin importar si es padre o hijo.
  const complejidadPadre = metaData.turno_complejidad_padre || 'media';
  const complejidadHijo = definitivos.complejidad_maxima || 'media';
  const hayJornadaCompleta = complejidadPadre === 'muy_compleja' || complejidadHijo === 'muy_compleja';

  let mensajeClienteFinal = metaData.mensaje_para_clienta;
  if (hayJornadaCompleta) {
    // Determinar hora correcta: la del turno con jornada completa
    const horaJornada = complejidadPadre === 'muy_compleja'
      ? (metaData.turno_hora_original || '09:00')
      : (definitivos.hora || '09:00');
    const horaIncorrecta = complejidadPadre === 'muy_compleja'
      ? (definitivos.hora || '12:00')
      : (metaData.turno_hora_original || '09:00');

    // Reemplazar hora incorrecta en el mensaje de la LLM
    if (horaIncorrecta !== horaJornada && mensajeClienteFinal.includes(horaIncorrecta)) {
      mensajeClienteFinal = mensajeClienteFinal.replace(horaIncorrecta, horaJornada);
      console.log(`[FormatearRespuesta] Hora corregida: ${horaIncorrecta} → ${horaJornada} (jornada completa)`);
    }
  }

  console.log(`[FormatearRespuesta] PATH A: Turno adicional creado. ` +
    `Row nuevo: #${turnoRowId}. Padre: #${metaData.turno_padre_row_id}`);

  return [{
    json: {
      success: true,
      accion: 'turno_adicional_creado',
      turno_id: turnoRowId,
      turno_id_padre: metaData.turno_padre_row_id,
      mensaje_para_clienta: mensajeClienteFinal,
      lead_row_id: metaData.lead_row_id,

      // Datos del turno adicional (solo servicio nuevo)
      servicio_agregado: {
        es_turno_adicional: true,
        odoo_turno_id: metaData.odoo_turno_id,
        servicio_nuevo: definitivos.servicio_detalle,
        trabajadora_nueva: prepararData.trabajadora || 'Companera',
        precio_servicio_nuevo: precioNuevo,
        sena_a_pagar: senaNuevo,
        link_pago: prepararData.mp_link,
        // Datos del turno padre (para contexto)
        servicio_existente: metaData.turno_servicio_existente || '',
        trabajadora_existente: metaData.turno_trabajadora_original || 'Leraysi',
        hora_existente: metaData.turno_hora_original || '',
        precio_existente: Number(metaData.turno_precio_existente) || 0,
      }
    }
  }];
}

// ============================================================================
// PATH B: MISMA TRABAJADORA — Fila existente actualizada (lógica v3 original)
// ============================================================================
const precioExistente = Number(metaData.turno_precio_existente) || 0;
const senaPagada = Number(metaData.turno_sena_pagada) || 0;
const precioTotal = definitivos.precio || 0;
const senaTotalNueva = definitivos.sena_monto || Math.round(precioTotal * 0.3);
const senaDiferencial = Math.max(0, senaTotalNueva - senaPagada);
const servicioExistente = metaData.turno_servicio_existente || '';

return [{
  json: {
    success: true,
    accion: metaData.accion,
    turno_id: turnoRowId,
    mensaje_para_clienta: metaData.mensaje_para_clienta,
    lead_row_id: metaData.lead_row_id,

    // Datos de servicio agregado (bloque combinado)
    servicio_agregado: {
      es_turno_adicional: false,
      odoo_turno_id: metaData.odoo_turno_id,
      servicios_combinados: definitivos.servicio_detalle,
      precio_total: precioTotal,
      link_pago: prepararData.mp_link,
      sena_ya_pagada: senaPagada,
      sena_adicional: senaDiferencial,
      sena_total_nueva: senaTotalNueva,
      servicio_existente: servicioExistente,
      precio_existente: precioExistente
    }
  }
}];

// ============================================================================
// FORMATEAR RESPUESTA OPCIONES - Agente Calendario Leraysi
// ============================================================================
// INPUT: AnalizarDisponibilidad (con slots_recomendados[])
// OUTPUT: Respuesta formateada con opciones de horario para la clienta
// Se usa solo en modo "consultar_disponibilidad" (bypass del LLM)
// ============================================================================

const data = $input.first().json;

// ============================================================================
// GATE DETERMINÍSTICO: si ParseInput bloqueó por datos faltantes
// ============================================================================
if (data.gate_bloqueado) {
  const faltantes = data.gate_datos_faltantes || ['email'];
  const nombre = data.nombre_clienta || 'Reina';

  const listaFaltantes = faltantes.map(d => `* Tu ${d}`).join('\n');

  console.log(`[FormatearRespuesta] 🛡️ GATE: devolviendo datos_faltantes (${faltantes.join(', ')})`);

  return [{
    json: {
      success: true,
      accion: 'datos_faltantes',
      mensaje_para_clienta: `${nombre}, para reservar tu turno necesito que me pases:\n\n${listaFaltantes}\n\n¿Me los compartís?`,
      opciones: [],
      datos_faltantes: faltantes,
      lead_row_id: data.lead_row_id || null
    }
  }];
}

const slots = data.slots_recomendados || [];
const servicioDisplay = data.servicio_detalle || (Array.isArray(data.servicio) ? data.servicio.join(' + ') : data.servicio) || 'servicio';
const nombreClienta = data.nombre_clienta || 'Reina';
const esAgregarServicio = data.agregar_a_turno_existente === true;
const horaOriginal = data.turno_hora_original || null;
const esSlotNoDisponible = data.accion === 'slot_no_disponible';
const horaDeseada = data.hora_deseada || null;

let accion;
let mensajeParaClienta;

// ── SLOT YA NO DISPONIBLE: race condition, presentar alternativas con contexto ──
if (esSlotNoDisponible && slots.length > 0) {
  accion = 'opciones_disponibles';

  const opcionesTexto = slots.map(s => {
    if (s.duracion_min >= 600) {
      return `* ${s.fecha_humana} - jornada completa (${s.hora_inicio} a ${s.hora_fin})`;
    }
    return `* ${s.fecha_humana} a las ${s.hora_inicio}`;
  }).join('\n');

  mensajeParaClienta = `${nombreClienta}, disculpa, el horario de las ${horaDeseada || '?'} ya no esta disponible. Te puedo ofrecer estas alternativas:\n\n${opcionesTexto}\n\n¿Cual te queda mejor?`;

} else if (esAgregarServicio && data.turno_complejidad_existente === 'muy_compleja') {
  // ── AGREGAR SERVICIO A JORNADA COMPLETA: confirmar directo sin opciones ──
  // La clienta ya va a estar todo el día — no tiene sentido ofrecer opciones de horario.
  const slotMismoDia = slots.find(s => !s.es_fecha_alternativa);

  if (slotMismoDia) {
    accion = 'confirmar_agregar_servicio_directo';

    const precioExistente = data.turno_precio_existente || 0;
    const precioNuevo = data.precio || 0;
    const precioTotal = precioExistente + precioNuevo;
    const senaPagada = data.turno_sena_pagada || Math.round(precioExistente * 0.3);
    const senaTotalNueva = Math.round(precioTotal * 0.3);
    const senaDiferencial = Math.max(0, senaTotalNueva - senaPagada);
    const servicioExistente = data.turno_servicio_existente || 'servicio actual';
    const fechaSlot = slotMismoDia.fecha_humana || 'tu turno';

    mensajeParaClienta = `⋆˚🧚‍♀️¡Genial mi vida! 💅 Voy a agregar ${servicioDisplay.toLowerCase()} a tu turno del ${fechaSlot} - Jornada completa.\n\n` +
      `📋 Resumen:\n` +
      `* ${servicioExistente}: $${precioExistente.toLocaleString('es-AR')}\n` +
      `* ${servicioDisplay}: $${precioNuevo.toLocaleString('es-AR')}\n` +
      `* Total: $${precioTotal.toLocaleString('es-AR')}\n\n` +
      `💰 Seña ya pagada: $${senaPagada.toLocaleString('es-AR')}\n` +
      `💰 Seña adicional a pagar: $${senaDiferencial.toLocaleString('es-AR')}\n\n` +
      `¿Me confirmas, reina? 🫶✨`;
  } else {
    // No cabe el mismo día — mensaje breve sin opciones
    accion = 'sin_disponibilidad_agregar';
    mensajeParaClienta = `${nombreClienta}, lamentablemente no podemos agregar ${servicioDisplay.toLowerCase()} a tu turno 😔 La agenda está completa ese día. ¿Querés agendarlo para otro día por separado?`;
  }

} else if (esAgregarServicio && slots.length > 0 && data.fecha_disponible === false && slots.every(s => s.servicio_reubicado && s.es_fecha_alternativa)) {
  // ── AGREGAR SERVICIO NO DISPONIBLE MISMO DÍA: ofrecer opciones claras ──
  // Caso: servicio muy_compleja (jornada completa) no cabe el día del turno existente.
  // NO forzar reprogramación — dar control a la clienta.
  accion = 'opciones_agregar_no_disponible';

  const servicioExistente = data.turno_servicio_existente || 'servicio actual';

  // Formatear fecha solicitada
  const fechaSolStr = data.fecha_solicitada || data.fecha_deseada || '';
  let fechaSolHumana = fechaSolStr;
  if (fechaSolStr) {
    const _dias = ['domingo','lunes','martes','miércoles','jueves','viernes','sábado'];
    const _meses = ['enero','febrero','marzo','abril','mayo','junio','julio','agosto','septiembre','octubre','noviembre','diciembre'];
    const fObj = new Date(fechaSolStr + 'T12:00:00');
    fechaSolHumana = `${_dias[fObj.getDay()]} ${fObj.getDate()} de ${_meses[fObj.getMonth()]}`;
  }

  // Fechas alternativas compactas: "martes 3, miércoles 4 o jueves 5"
  const fechasAlt = slots.map(s => {
    const parts = s.fecha_humana.split(' ');
    return `${parts[0]} ${parts[1]}`;
  }).join(', ').replace(/, ([^,]+)$/, ' o $1');

  mensajeParaClienta = `${nombreClienta}, no es posible agregar ${servicioDisplay.toLowerCase()} a tu turno del ${fechaSolHumana} 😔\n\n` +
    `${servicioDisplay} requiere jornada completa (09:00 a 19:00) y ese día la agenda está llena.\n\n` +
    `¿Qué preferís hacer?\n\n` +
    `1️⃣ Mantener tu ${servicioExistente} el ${fechaSolHumana} a las ${horaOriginal} como está\n` +
    `2️⃣ Reprogramar todo junto en jornada completa (${fechasAlt})\n` +
    `3️⃣ Agendar ${servicioDisplay.toLowerCase()} por separado en otro día\n\n` +
    `Decime y lo coordinamos 💅`;

} else if (esAgregarServicio && slots.length > 0) {
  // ── AGREGAR SERVICIO: opciones con contexto de cambio horario + desglose seña ──
  accion = 'opciones_agregar_servicio';

  const opcionesTexto = slots.map(s => {
    if (s.es_turno_adicional) {
      // Turno adicional: otra trabajadora hace solo el servicio nuevo
      // La hora de llegada NO cambia — excelente UX
      if (!s.es_fecha_alternativa && horaOriginal) {
        return `* ${s.fecha_humana} - ${s.trabajadora} hace tu ${servicioDisplay.toLowerCase()} a las ${s.hora_inicio} (vos llegas a las ${horaOriginal} como estaba previsto)`;
      }
      return `* ${s.fecha_humana} a las ${s.hora_inicio} con ${s.trabajadora}`;
    }
    if (s.duracion_min >= 600) {
      return `* ${s.fecha_humana} - jornada completa (${s.hora_inicio} a ${s.hora_fin}, tu servicio actual se acomoda dentro)`;
    }
    if (horaOriginal && s.hora_inicio === horaOriginal && !s.es_fecha_alternativa) {
      return `* ${s.fecha_humana} a las ${s.hora_inicio} (tu horario actual se mantiene)`;
    }
    if (horaOriginal && !s.es_fecha_alternativa) {
      return `* ${s.fecha_humana} a las ${s.hora_inicio} (tu turno se moveria de ${horaOriginal} a ${s.hora_inicio})`;
    }
    return `* ${s.fecha_humana} a las ${s.hora_inicio}`;
  }).join('\n');

  // Calcular desglose de seña para agregar servicio
  const precioExistente = data.turno_precio_existente || 0;
  const precioNuevo = data.precio || 0;
  // Turno adicional: seña solo del servicio nuevo. Bloque combinado: seña diferencial
  const hayTurnoAdicional = slots.some(s => s.es_turno_adicional);
  const precioTotal = hayTurnoAdicional ? precioNuevo : (precioExistente + precioNuevo);
  const senaPagada = hayTurnoAdicional ? 0 : (data.turno_sena_pagada || Math.round(precioExistente * 0.3));
  const senaTotalNueva = Math.round(precioTotal * 0.3);
  const senaDiferencial = Math.max(0, senaTotalNueva - senaPagada);

  const servicioExistente = data.turno_servicio_existente || 'servicio actual';

  let desgloseSena;
  if (hayTurnoAdicional) {
    desgloseSena = `\n\n📋 Servicio adicional:\n` +
      `* ${servicioDisplay}: $${precioNuevo.toLocaleString('es-AR')}\n` +
      `💰 Seña a pagar: $${senaDiferencial.toLocaleString('es-AR')}\n` +
      `(tu turno de ${servicioExistente} a las ${horaOriginal || '?'} no cambia)`;
  } else {
    desgloseSena = `\n\n📋 Resumen del turno actualizado:\n` +
      `* ${servicioExistente}: $${precioExistente.toLocaleString('es-AR')}\n` +
      `* ${servicioDisplay}: $${precioNuevo.toLocaleString('es-AR')}\n` +
      `* Total: $${(precioExistente + precioNuevo).toLocaleString('es-AR')}\n\n` +
      `💰 Seña ya pagada: $${(data.turno_sena_pagada || Math.round(precioExistente * 0.3)).toLocaleString('es-AR')}\n` +
      `💰 Seña adicional a pagar: $${senaDiferencial.toLocaleString('es-AR')}`;
  }

  mensajeParaClienta = `${nombreClienta}, para agregar ${servicioDisplay.toLowerCase()} a tu turno, estas son las opciones:\n\n${opcionesTexto}${desgloseSena}\n\n¿Cual te queda mejor?`;

} else if (slots.length > 0) {
  // ── TURNO NUEVO: opciones normales ──
  accion = 'opciones_disponibles';

  const esJornadaCompleta = slots.some(s => s.duracion_min >= 600);

  const opcionesTexto = slots.map(s => {
    if (s.en_proceso) {
      return `* ${s.fecha_humana} a las ${s.hora_inicio} (aprovechando tiempo de proceso)`;
    }
    if (s.duracion_min >= 600) {
      return `* ${s.fecha_humana} - jornada completa (${s.hora_inicio} a ${s.hora_fin})`;
    }
    return `* ${s.fecha_humana} a las ${s.hora_inicio}`;
  }).join('\n');

  if (esJornadaCompleta) {
    mensajeParaClienta = `${nombreClienta}, como ${servicioDisplay.toLowerCase()} es un servicio extenso, necesitamos una jornada completa. Tengo disponibles estos días:\n\n${opcionesTexto}\n\n¿Cuál te queda mejor?`;
  } else {
    mensajeParaClienta = `${nombreClienta}, para ${servicioDisplay.toLowerCase()} tengo estos horarios:\n\n${opcionesTexto}\n\n¿Cuál te queda mejor?`;
  }
} else {
  // ── SIN DISPONIBILIDAD ──
  accion = esAgregarServicio ? 'sin_disponibilidad_agregar' : 'sin_disponibilidad';

  const alternativas = data.alternativas || [];
  if (alternativas.length > 0) {
    const altTexto = alternativas.map(a =>
      `* ${a.nombre_dia} ${a.fecha}`
    ).join('\n');
    mensajeParaClienta = esAgregarServicio
      ? `${nombreClienta}, no es posible agregar ${servicioDisplay.toLowerCase()} a tu turno ese dia. Te puedo ofrecer estos dias:\n\n${altTexto}\n\n¿Cual te queda mejor?`
      : `${nombreClienta}, no encontré horarios disponibles para ${servicioDisplay.toLowerCase()} en la fecha que pediste. Te puedo ofrecer estos días:\n\n${altTexto}\n\n¿Cuál te queda mejor?`;
  } else {
    mensajeParaClienta = esAgregarServicio
      ? `${nombreClienta}, no es posible agregar ${servicioDisplay.toLowerCase()} a tu turno en los proximos dias. Ambas estilistas tienen la agenda completa.`
      : `${nombreClienta}, no encontré horarios disponibles para ${servicioDisplay.toLowerCase()} en los próximos días. ¿Querés que busque en otra fecha?`;
  }
}

return [{
  json: {
    success: true,
    accion,
    mensaje_para_clienta: mensajeParaClienta,
    opciones: accion === 'confirmar_agregar_servicio_directo'
      ? slots.filter(s => !s.es_fecha_alternativa)
      : slots,
    lead_row_id: data.lead_row_id || null,
    // Precio determinístico para que Master Agent cotice correctamente
    precio: data.precio || 0,
    sena: Math.round((data.precio || 0) * 0.3),
    duracion_estimada: data.duracion_estimada || 0,
    complejidad_maxima: data.complejidad_maxima || 'media',
    // Contexto agregar servicio (para que Master Agent sepa el flujo)
    agregar_a_turno_existente: esAgregarServicio,
    turno_id_existente: data.turno_id_existente || null,
    turno_precio_existente: data.turno_precio_existente || null,
    turno_hora_original: horaOriginal,
    // Desglose seña (solo relevante cuando esAgregarServicio)
    turno_sena_pagada: data.turno_sena_pagada || null,
    turno_servicio_existente: data.turno_servicio_existente || null
  }
}];

// ============================================================================
// ROUTE DECISION - Nodo decisor determinístico
// ============================================================================
// POSICIÓN: AnalizarDisponibilidad → [RouteDecision] → SwitchModo
//
// Este nodo tiene TODAS las cartas:
//   - Lo que la LLM envió (modo, accion, agregar_a_turno_existente, etc.)
//   - Lo que el analyzer encontró (opciones, disponible, slots_recomendados)
//
// RESPONSABILIDAD: Decidir `modo` y `accion` de forma determinística.
// SwitchModo solo bifurca basándose en lo que este nodo decide.
// No importa si la LLM falló en enviar modo/accion — este nodo corrige.
// ============================================================================

const data = $input.first().json;

// === Datos de la LLM (pueden ser null) ===
const modoLLM = data.modo;
const accionLLM = data.accion;

// === Datos del analyzer (realidad) ===
const opciones = data.opciones || data.slots_recomendados || [];
const disponible = data.disponible === true;

// === Contexto del request ===
const gateBloqueado = data.gate_bloqueado === true;
const agregarATurnoExistente = data.agregar_a_turno_existente === true;
const turnoAgendado = data.turno_agendado === true;

// === Hora y fecha solicitadas ===
const fechaSolicitadaRaw = data.fecha_solicitada || data.fecha_deseada || '';
const fechaSoloParte = fechaSolicitadaRaw.includes('T')
  ? fechaSolicitadaRaw.split('T')[0]
  : fechaSolicitadaRaw.split(' ')[0];
const horaDeseada = data.hora_deseada || '';

// ============================================================================
// VERIFICAR SI EL SLOT EXACTO SOLICITADO ESTÁ EN LAS OPCIONES
// ============================================================================
// Compara fecha + hora solicitada contra las opciones del analyzer.
// Si ninguna opción coincide → el slot NO está disponible.
const slotExactoDisponible = opciones.some(o =>
  o.fecha === fechaSoloParte && o.hora_inicio === horaDeseada
);

// ============================================================================
// DECISION TREE — DETERMINÍSTICO
// ============================================================================
let modo, accion, motivo;

// 1. GATE BLOQUEADO: faltan datos obligatorios → bypass directo
if (gateBloqueado) {
  modo = 'consultar_disponibilidad';
  accion = 'datos_faltantes';
  motivo = `Gate bloqueado: faltan ${(data.gate_datos_faltantes || []).join(', ')}`;
}

// 2. LLM PIDIÓ CONSULTAR: primera llamada del flujo dos-pasos → siempre respetar
else if (modoLLM === 'consultar_disponibilidad') {
  modo = 'consultar_disponibilidad';
  if (agregarATurnoExistente) {
    accion = 'consultar_agregar_servicio';
  } else if (accionLLM === 'reprogramar') {
    accion = 'consultar_reprogramar';
  } else {
    accion = 'consultar_turno_nuevo';
  }
  motivo = `LLM pidió consultar explícitamente (accion: ${accion})`;
}

// 3. SIN DISPONIBILIDAD: ni el slot ni alternativas
else if (!disponible || opciones.length === 0) {
  modo = 'consultar_disponibilidad';
  accion = 'sin_disponibilidad';
  motivo = 'Analyzer: sin disponibilidad';
}

// 4. SLOT EXACTO DISPONIBLE: la hora+fecha solicitada existe → agendar
else if (slotExactoDisponible) {
  modo = 'agendar';
  if (agregarATurnoExistente) {
    accion = 'agregar_servicio';
  } else if (accionLLM === 'reprogramar') {
    accion = 'reprogramar';
  } else {
    accion = 'agendar_turno_nuevo';
  }
  motivo = `Slot ${horaDeseada} en ${fechaSoloParte} disponible`;
}

// 5. JORNADA COMPLETA + AGREGAR SERVICIO + AGENDAR: rutear directo
//    LLM envía hora 09:00 (llegada) pero el slot real es otro (ej: 12:00 Compañera).
//    El slot exacto no matchea (09:00 ≠ 12:00) pero HAY slot mismo día → agendar.
//    NO mutar hora_deseada — downstream ya maneja 09:00 (cliente) vs 12:00 (interno).
else if (modoLLM === 'agendar' && agregarATurnoExistente &&
         data.turno_complejidad_existente === 'muy_compleja' &&
         opciones.some(o => o.fecha === fechaSoloParte && !o.es_fecha_alternativa)) {
  modo = 'agendar';
  accion = 'agregar_servicio';
  motivo = `Jornada completa: slot mismo día disponible, ruteo directo a agendar`;
}

// 6. SLOT NO DISPONIBLE + HAY ALTERNATIVAS: presentar opciones
//    Este es el caso de race condition (slot se ocupó entre consulta y confirmación)
else {
  modo = 'consultar_disponibilidad';
  accion = 'slot_no_disponible';
  motivo = `Slot ${horaDeseada} en ${fechaSoloParte} NO disponible. ${opciones.length} alternativas`;
}

console.log(`[RouteDecision] modo=${modo} | accion=${accion} | ${motivo}`);

// ============================================================================
// OUTPUT: misma data + modo y accion decididos
// ============================================================================
return [{
  json: {
    ...data,
    modo,
    accion,
    _route_decision: {
      modo_llm: modoLLM || null,
      accion_llm: accionLLM || null,
      slot_exacto_disponible: slotExactoDisponible,
      total_opciones: opciones.length,
      motivo
    }
  }
}];
